export const scene: DialogueEntry[] = [
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "07:25。", background: Background.Chapter_8_Ch8_Act1_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "校史館側廊。", background: Background.Chapter_8_Ch8_Act1_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "顧言靠在消防箱旁邊的凹壁裡。側廊很長，兩邊是玻璃展櫃，櫃裡擺著黑白舊照片和發黃的校史文件。冷白色的日光燈打在玻璃上，和窗外灰色的雨光混在一起，把整條走廊照得像一條沒有溫度的隧道。", background: Background.Chapter_8_Ch8_Act1_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他在等。", background: Background.Chapter_8_Ch8_Act1_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "不是猜的。是記的。第六輪、第七輪，許星棠都會在這個時間從校史館側門出來，走這條廊去暗房。她比所有工作人員都早。因為她不是來幫忙的——她是來看的。", background: Background.Chapter_8_Ch8_Act1_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）⋯⋯來了。", background: Background.Chapter_8_Ch8_Act1_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "腳步聲從走廊盡頭傳過來。很穩。不急。膠底鞋踩在磁磚上的節奏太均勻了——和所有校慶裡隨意走動的人不一樣。", background: Background.Chapter_8_Ch8_Act1_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "許星棠從轉角出現。", background: Background.Chapter_8_Ch8_Act1_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "攝影背心。藍色工作證。相機掛在脖子上。碎髮被濕氣黏在耳側。她走路的時候不看兩邊的展櫃，只看前方。像一個已經把這條路走過很多次的人。", background: Background.Chapter_8_Ch8_Act1_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她看見他了。", background: Background.Chapter_8_Ch8_Act1_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "腳步沒有停。沒有減速。她繼續往前走，經過他面前——", background: Background.Chapter_8_Ch8_Act1_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "然後停了。", background: Background.Chapter_8_Ch8_Act1_S0 },
    { characterId: CharacterId.XuXingtang, character: "許星棠", dialogue: "你比上次早。", background: Background.Chapter_8_Ch8_Act1_S0, portrait: Portrait.XuXingtang_Cold },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "不是問句。是確認。語氣平得像在說今天雨沒停。", background: Background.Chapter_8_Ch8_Act1_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "嗯。", background: Background.Chapter_8_Ch8_Act1_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.XuXingtang, character: "許星棠", dialogue: "換了地方。", background: Background.Chapter_8_Ch8_Act1_S0, portrait: Portrait.XuXingtang_Cold },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "上次被林主任看見過。", background: Background.Chapter_8_Ch8_Act1_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "許星棠看了他一眼。那一眼很短。不到一秒。但顧言知道她在確認的東西比「換了地方」更多——她在確認他是不是又來重複那一套時間循環的說辭。", background: Background.Chapter_8_Ch8_Act1_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）不要重複。", background: Background.Chapter_8_Ch8_Act1_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）第六輪我花了半個小時解釋循環。她聽完之後說「忘了我說的」。", background: Background.Chapter_8_Ch8_Act1_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）第七輪她比第六輪快一點。但還是花了十五分鐘。", background: Background.Chapter_8_Ch8_Act1_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）這一輪——", background: Background.Chapter_8_Ch8_Act1_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）不解釋。", background: Background.Chapter_8_Ch8_Act1_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）直接給她只有合作過才會知道的東西。", background: Background.Chapter_8_Ch8_Act1_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "空相機包是誘餌。", background: Background.Chapter_8_Ch8_Act1_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "許星棠的表情沒有變。但她停下了往暗房走的動作。肩膀的角度偏了半度——朝向他。", background: Background.Chapter_8_Ch8_Act1_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "不是失誤。是有人故意讓相機包空著放在那裡，等妳去拿。", background: Background.Chapter_8_Ch8_Act1_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.XuXingtang, character: "許星棠", dialogue: "⋯⋯", background: Background.Chapter_8_Ch8_Act1_S0, portrait: Portrait.XuXingtang_Cold },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "加密檔案的名稱裡有「GZ」。", background: Background.Chapter_8_Ch8_Act1_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "還有「給小言」。", background: Background.Chapter_8_Ch8_Act1_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "走廊裡安靜了。", background: Background.Chapter_8_Ch8_Act1_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "不是那種沒有聲音的安靜。是雨聲還在打窗戶、日光燈還在嗡響、但兩個人之間的空氣突然被抽掉了一層的那種安靜。", background: Background.Chapter_8_Ch8_Act1_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "許星棠看著他。她的眼睛很亮——不是熱情的亮，是深水一樣的、安靜的亮。看得到表面。猜不到深度。", background: Background.Chapter_8_Ch8_Act1_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "但水面下面有東西動了一下。", background: Background.Chapter_8_Ch8_Act1_S0 },
    { characterId: CharacterId.XuXingtang, character: "許星棠", dialogue: "你怎麼知道檔案名稱。", background: Background.Chapter_8_Ch8_Act1_S0, portrait: Portrait.XuXingtang_Cold },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "陳述句。不是問句。她的聲音沒有升高。沒有顫抖。每一個字都像被精確控制過——不大到被第三個人聽見，也不小到讓他聽不清。", background: Background.Chapter_8_Ch8_Act1_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）她沒有問循環。她問的是檔案名稱。", background: Background.Chapter_8_Ch8_Act1_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）——而我說出來了。", background: Background.Chapter_8_Ch8_Act1_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "妳給我看過。", background: Background.Chapter_8_Ch8_Act1_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.XuXingtang, character: "許星棠", dialogue: "我沒有給任何人看過。", background: Background.Chapter_8_Ch8_Act1_S0, portrait: Portrait.XuXingtang_Cold },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "我知道。", background: Background.Chapter_8_Ch8_Act1_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他沒有解釋。他看著她。她也看著他。兩個人之間隔著三步的距離和一整條走廊的冷光。", background: Background.Chapter_8_Ch8_Act1_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "林主任 21:45 會動基座。", background: Background.Chapter_8_Ch8_Act1_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "但他不是終點。", background: Background.Chapter_8_Ch8_Act1_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.XuXingtang, character: "許星棠", dialogue: "⋯⋯", background: Background.Chapter_8_Ch8_Act1_S0, portrait: Portrait.XuXingtang_Cold },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "22:58 開後台門的人不是他。", background: Background.Chapter_8_Ch8_Act1_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "許星棠的手指動了一下。很細微。相機帶子在她指間被捏緊了半秒，然後鬆開。", background: Background.Chapter_8_Ch8_Act1_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "那是她第一次在這條走廊上露出不是「節制」的東西。", background: Background.Chapter_8_Ch8_Act1_S0 },
    { characterId: CharacterId.XuXingtang, character: "許星棠", dialogue: "誰。", background: Background.Chapter_8_Ch8_Act1_S0, portrait: Portrait.XuXingtang_Cold },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "邵叔。", background: Background.Chapter_8_Ch8_Act1_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "兩個字。", background: Background.Chapter_8_Ch8_Act1_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "走廊裡的日光燈嗡了一聲。窗外雨打玻璃的節奏沒有變。但那兩個字落地之後，許星棠的肩膀線條變了——不是放鬆，是繃緊。像一根弦被撥了一下，還在震，但沒有發出聲音。", background: Background.Chapter_8_Ch8_Act1_S0 },
    { characterId: CharacterId.XuXingtang, character: "許星棠", dialogue: "⋯⋯", background: Background.Chapter_8_Ch8_Act1_S0, portrait: Portrait.XuXingtang_Cold },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "22:50。他會以後台清場的名義離開指揮區。", background: Background.Chapter_8_Ch8_Act1_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "22:58。他用安全權限打開設備通道的門。", background: Background.Chapter_8_Ch8_Act1_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "那道門後面是直播備份線。", background: Background.Chapter_8_Ch8_Act1_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "妳在那裡。", background: Background.Chapter_8_Ch8_Act1_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "許星棠沒有說話。", background: Background.Chapter_8_Ch8_Act1_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她看著他。很久。比剛才任何一次都久。她的嘴唇壓緊了。不是恐懼。是——在重新計算。", background: Background.Chapter_8_Ch8_Act1_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）她在算。", background: Background.Chapter_8_Ch8_Act1_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她的呼吸慢了半拍。", background: Background.Chapter_8_Ch8_Act1_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）算我到底知道了多少。", background: Background.Chapter_8_Ch8_Act1_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）⋯⋯她不會因為「時間循環」四個字相信我。", background: Background.Chapter_8_Ch8_Act1_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）但她會因為「我說出了她沒有告訴任何人的東西」而不得不面對一個問題——", background: Background.Chapter_8_Ch8_Act1_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）——要嘛我在說實話。要嘛有人比我更早查到了她。", background: Background.Chapter_8_Ch8_Act1_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）不管是哪一個，她都不能再一個人走了。", background: Background.Chapter_8_Ch8_Act1_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "許星棠深吸了一口氣。很輕。如果不是走廊太安靜，他聽不到。", background: Background.Chapter_8_Ch8_Act1_S0 },
    { characterId: CharacterId.XuXingtang, character: "許星棠", dialogue: "你說的這些，我沒有告訴過任何人。", background: Background.Chapter_8_Ch8_Act1_S0, portrait: Portrait.XuXingtang_Cold },
    { characterId: CharacterId.XuXingtang, character: "許星棠", dialogue: "檔案名稱沒有。基座的時間沒有。後台門沒有。", background: Background.Chapter_8_Ch8_Act1_S0, portrait: Portrait.XuXingtang_Cold },
    { characterId: CharacterId.XuXingtang, character: "許星棠", dialogue: "邵叔——", background: Background.Chapter_8_Ch8_Act1_S0, portrait: Portrait.XuXingtang_Cold },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她停了一下。那個名字在她嘴裡停了半秒才出來。像一塊太重的石頭，從喉嚨裡慢慢推出去。", background: Background.Chapter_8_Ch8_Act1_S0 },
    { characterId: CharacterId.XuXingtang, character: "許星棠", dialogue: "邵叔也沒有。", background: Background.Chapter_8_Ch8_Act1_S0, portrait: Portrait.XuXingtang_Cold },
    { characterId: CharacterId.XuXingtang, character: "許星棠", dialogue: "你是怎麼知道的。", background: Background.Chapter_8_Ch8_Act1_S0, portrait: Portrait.XuXingtang_Cold },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "⋯⋯", background: Background.Chapter_8_Ch8_Act1_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）怎麼知道的。", background: Background.Chapter_8_Ch8_Act1_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）我死過七次。", background: Background.Chapter_8_Ch8_Act1_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）第一次把訊息交給他，他把我提前清除了。第二次我上校務車，車翻了。第三次我信任安全流程，流程把我關進醫務室。第四次我追到地下泵房。第五次我清醒活過 22:22，看見妳在 23:00 死了。第六次我找妳合作。第七次我測出了邵叔。", background: Background.Chapter_8_Ch8_Act1_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）⋯⋯但這些不能現在說。", background: Background.Chapter_8_Ch8_Act1_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）不是因為她不會信。是因為說了循環，她會開始懷疑這些資訊是不是循環裡的幻覺。", background: Background.Chapter_8_Ch8_Act1_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）先給結論。循環的事，等她問了再說。", background: Background.Chapter_8_Ch8_Act1_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "妳查了很久。", background: Background.Chapter_8_Ch8_Act1_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "我查的時間比妳以為的長。", background: Background.Chapter_8_Ch8_Act1_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.XuXingtang, character: "許星棠", dialogue: "那不是回答。", background: Background.Chapter_8_Ch8_Act1_S0, portrait: Portrait.XuXingtang_Cold },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "是。", background: Background.Chapter_8_Ch8_Act1_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "但現在只有這個。", background: Background.Chapter_8_Ch8_Act1_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "許星棠看著他。三秒。五秒。雨打在窗戶上。展櫃裡的舊照片在冷光下一動不動。", background: Background.Chapter_8_Ch8_Act1_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "然後她做了一個顧言沒見過的動作——她把相機從脖子上取下來。雙手捧著。不是要遞給他。是把它收回自己胸前，用兩手護住。", background: Background.Chapter_8_Ch8_Act1_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "像在確認它還在。", background: Background.Chapter_8_Ch8_Act1_S0 },
    { characterId: CharacterId.XuXingtang, character: "許星棠", dialogue: "如果你說的是真的。", background: Background.Chapter_8_Ch8_Act1_S0, portrait: Portrait.XuXingtang_Cold },
    { characterId: CharacterId.XuXingtang, character: "許星棠", dialogue: "這次你想怎麼做。", background: Background.Chapter_8_Ch8_Act1_S0, portrait: Portrait.XuXingtang_Cold },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她的聲音沒有變。還是平的。還是低的。還是每一個字都像被精確控制過。但問句本身——是第一次。", background: Background.Chapter_8_Ch8_Act1_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）前幾輪她說的都是陳述句。「今天不要靠近鐘樓。」「不管誰說要幫你保管相機，都不要給。」「你問的問題，我沒有答案。」", background: Background.Chapter_8_Ch8_Act1_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）這一次她問了。", background: Background.Chapter_8_Ch8_Act1_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）⋯⋯她動搖了。", background: Background.Chapter_8_Ch8_Act1_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）比第六輪快。比第七輪快。", background: Background.Chapter_8_Ch8_Act1_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）不是因為她信了循環。是因為——", background: Background.Chapter_8_Ch8_Act1_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）——她查了這麼久，第一次有人比她更早走到了她還沒走到的地方。", background: Background.Chapter_8_Ch8_Act1_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）她不能假裝這件事不存在。", background: Background.Chapter_8_Ch8_Act1_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "先讓他相信。", background: Background.Chapter_8_Ch8_Act1_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "我不會再出現。", background: Background.Chapter_8_Ch8_Act1_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "許星棠的眼睛動了一下。不是驚訝。是——沒有聽懂。或者聽懂了，但不確定他是不是認真的。", background: Background.Chapter_8_Ch8_Act1_S0 },
    { characterId: CharacterId.XuXingtang, character: "許星棠", dialogue: "什麼意思。", background: Background.Chapter_8_Ch8_Act1_S0, portrait: Portrait.XuXingtang_Cold },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "讓他以為我死了。", background: Background.Chapter_8_Ch8_Act1_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "走廊裡又安靜了。", background: Background.Chapter_8_Ch8_Act1_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "這一次的安靜比剛才更重。因為「讓他以為我死了」這六個字，不是一個計畫的開頭。是一個已經想完了所有退路的人，說出來的最後一句話。", background: Background.Chapter_8_Ch8_Act1_S0 },
    { characterId: CharacterId.XuXingtang, character: "許星棠", dialogue: "⋯⋯", background: Background.Chapter_8_Ch8_Act1_S0, portrait: Portrait.XuXingtang_Cold },
    { characterId: CharacterId.XuXingtang, character: "許星棠", dialogue: "相機怎麼送出去。", background: Background.Chapter_8_Ch8_Act1_S0, portrait: Portrait.XuXingtang_Cold },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她沒有問「你瘋了嗎」。沒有問「為什麼」。沒有問「你怎麼做到」。", background: Background.Chapter_8_Ch8_Act1_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她問的是相機。", background: Background.Chapter_8_Ch8_Act1_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）⋯⋯對。", background: Background.Chapter_8_Ch8_Act1_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）這才是她。", background: Background.Chapter_8_Ch8_Act1_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）她不會被我嚇到。她不會因為「假死」兩個字就退縮。", background: Background.Chapter_8_Ch8_Act1_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）她會先問——然後呢。計畫的每一個環節怎麼落地。她站在哪裡才不會再被拖進死角。", background: Background.Chapter_8_Ch8_Act1_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）她是共同策劃的人。不是被告知作戰的人。", background: Background.Chapter_8_Ch8_Act1_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "相機不送出去。", background: Background.Chapter_8_Ch8_Act1_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "在妳身上。", background: Background.Chapter_8_Ch8_Act1_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.XuXingtang, character: "許星棠", dialogue: "密碼呢。", background: Background.Chapter_8_Ch8_Act1_S0, portrait: Portrait.XuXingtang_Cold },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "我來。", background: Background.Chapter_8_Ch8_Act1_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.XuXingtang, character: "許星棠", dialogue: "韓越能不能信。", background: Background.Chapter_8_Ch8_Act1_S0, portrait: Portrait.XuXingtang_Cold },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "能。", background: Background.Chapter_8_Ch8_Act1_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "第七輪我測過他。他沒有洩密。", background: Background.Chapter_8_Ch8_Act1_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.XuXingtang, character: "許星棠", dialogue: "你測過他。", background: Background.Chapter_8_Ch8_Act1_S0, portrait: Portrait.XuXingtang_Cold },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "嗯。", background: Background.Chapter_8_Ch8_Act1_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.XuXingtang, character: "許星棠", dialogue: "邵叔如果提前動手。", background: Background.Chapter_8_Ch8_Act1_S0, portrait: Portrait.XuXingtang_Cold },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "他不會。", background: Background.Chapter_8_Ch8_Act1_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "他要等我先走進他的陷阱。", background: Background.Chapter_8_Ch8_Act1_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.XuXingtang, character: "許星棠", dialogue: "直播被切。", background: Background.Chapter_8_Ch8_Act1_S0, portrait: Portrait.XuXingtang_Cold },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "備援。不只一條線。", background: Background.Chapter_8_Ch8_Act1_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.XuXingtang, character: "許星棠", dialogue: "我站在哪裡。", background: Background.Chapter_8_Ch8_Act1_S0, portrait: Portrait.XuXingtang_Cold },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "⋯⋯", background: Background.Chapter_8_Ch8_Act1_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）她在問最後一個問題。", background: Background.Chapter_8_Ch8_Act1_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）不是問她自己要躲在哪裡。是問——在整個計畫裡，她的位置是什麼。她不是餌。不是被保護的人。不是等著被告知結果的人。", background: Background.Chapter_8_Ch8_Act1_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）她要知道自己站在哪裡，才能知道自己要做什麼。", background: Background.Chapter_8_Ch8_Act1_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "門檻上。", background: Background.Chapter_8_Ch8_Act1_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "22:58。那道門。", background: Background.Chapter_8_Ch8_Act1_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "前幾輪妳被拖進門後。", background: Background.Chapter_8_Ch8_Act1_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "這一輪——", background: Background.Chapter_8_Ch8_Act1_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "妳停在門檻上。", background: Background.Chapter_8_Ch8_Act1_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "一步後退是死角。一步往前是鏡頭。", background: Background.Chapter_8_Ch8_Act1_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "妳不退。", background: Background.Chapter_8_Ch8_Act1_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "許星棠看著他。很久。", background: Background.Chapter_8_Ch8_Act1_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她的手還捧著相機。指節沒有發白。呼吸沒有亂。她的表情還是那種節制——不是冷漠，是一個知道自己沒有重來機會的人，把所有力氣都收進了最必要的字裡。", background: Background.Chapter_8_Ch8_Act1_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "但她點了一下頭。", background: Background.Chapter_8_Ch8_Act1_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "很輕。很短。下巴動了不到一公分的幅度。", background: Background.Chapter_8_Ch8_Act1_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "那是她第一次在這條走廊上，對他做出「同意」的動作。", background: Background.Chapter_8_Ch8_Act1_S0 },
    { characterId: CharacterId.XuXingtang, character: "許星棠", dialogue: "韓越在哪裡。", background: Background.Chapter_8_Ch8_Act1_S0, portrait: Portrait.XuXingtang_Cold },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "妳帶他來。", background: Background.Chapter_8_Ch8_Act1_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "08:10。暗房。", background: Background.Chapter_8_Ch8_Act1_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.XuXingtang, character: "許星棠", dialogue: "⋯⋯", background: Background.Chapter_8_Ch8_Act1_S0, portrait: Portrait.XuXingtang_Cold },
    { characterId: CharacterId.XuXingtang, character: "許星棠", dialogue: "你還沒有解釋你是怎麼知道這些的。", background: Background.Chapter_8_Ch8_Act1_S0, portrait: Portrait.XuXingtang_Cold },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "嗯。", background: Background.Chapter_8_Ch8_Act1_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "等計畫說完。", background: Background.Chapter_8_Ch8_Act1_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "許星棠看了他最後一眼。那一眼比之前所有的都長。不是在確認他是不是在說謊。是在確認——如果她把相機和命都押在這個人身上，他會不會接得住。", background: Background.Chapter_8_Ch8_Act1_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她沒有說出答案。", background: Background.Chapter_8_Ch8_Act1_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她轉身。往暗房的方向走了。", background: Background.Chapter_8_Ch8_Act1_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "腳步聲重新開始——和來時一樣均勻、一樣穩。", background: Background.Chapter_8_Ch8_Act1_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "顧言靠回牆上。", background: Background.Chapter_8_Ch8_Act1_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "手還在抖。不是因為冷。是因為——她點頭了。", background: Background.Chapter_8_Ch8_Act1_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）⋯⋯", background: Background.Chapter_8_Ch8_Act1_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）她信了嗎。", background: Background.Chapter_8_Ch8_Act1_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）不。", background: Background.Chapter_8_Ch8_Act1_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）她沒有信。", background: Background.Chapter_8_Ch8_Act1_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）她只是確認了一件事——我說的東西，只有一種來源能知道。", background: Background.Chapter_8_Ch8_Act1_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）而那個來源，不管是什麼，都比她一個人查更遠。", background: Background.Chapter_8_Ch8_Act1_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）⋯⋯夠了。", background: Background.Chapter_8_Ch8_Act1_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）這一輪不需要她完全相信我。", background: Background.Chapter_8_Ch8_Act1_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）需要的是——她不再一個人走。", background: Background.Chapter_8_Ch8_Act1_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "07:30。", background: Background.Chapter_8_Ch8_Act1_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "雨還在下。展櫃裡的舊照片一動不動。黑白的人影站在十年前的校門口，笑著，不知道十年後會有人站在這條走廊上，用六個字換一個點頭。", background: Background.Chapter_8_Ch8_Act1_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "讓他以為我死了。", background: Background.Chapter_8_Ch8_Act1_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她問了怎麼做。", background: Background.Chapter_8_Ch8_Act1_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "這就是開始。", background: Background.Chapter_8_Ch8_Act1_S0 },
];
